parameters.jsCode:
const items = $input.all();
const output = [];

for (const item of items) {
  for (const [key, value] of Object.entries(item.json)) {
    if (!value) continue;

    const client = JSON.parse(value);

    output.push({
      json: {
        id: client.id,
        name: client.name,
        phone: client.phone,
      },
    });
  }
}

return output;

