}

text = String(text || '');

const charCount = text.length;

const milliseconds = Math.max(
  400,
  Math.min(3000, Math.round((charCount / 40) * 1000))
);

return [
  {
    json: {
      ...data.json,
      delay: milliseconds,
    }
  }
];

